/**
 * Set of color palettes to be used in visualizations
 * @public
 */
export const colorPaletteOptions = [
  ...themedColoringOptions,
  ...automaticColoringOptions,
  ...sequentialColoringOptions,
  ...divergingColoringOptions,
] as const;

/**
 * Representation of a color palette, chosen from predefined options.
 * @public
 */
export type ColorPalette = (typeof colorPaletteOptions)[number];

/**
 * Representation of a custom color palette
 * @public
 */
export type CustomColorPalette = Record<string, string> | string[];

/** @internal */
export type ThemedColorPalette = (typeof themedColoringOptions)[number];

/** @internal */
export type AutomaticColorPalette = (typeof automaticColoringOptions)[number];

/** @internal */
export type SequentialColorPalette = (typeof sequentialColoringOptions)[number];

/** @internal */
export type DivergingColorPalette = (typeof divergingColoringOptions)[number];

/** @internal */
export type ColorPaletteDefinition = Record<string, { Default: string }>;

/**
 * Mode in which bars are colored when single dimension data is shown
 * @public
 */
export const colorPaletteModeOptions = ['single-color', 'multi-color'] as const;
/**
 * @public
 */
export type ColorPaletteMode = (typeof colorPaletteModeOptions)[number];

/**
 * Color for a timeseries in different actions.
 * Internal use only. Do not use.
 * @public
 */
export interface ColorToken {
  Default: string;
}

/**
 * @internal
 */
export interface ShapeColor {
  color: string;
  stroke?: string;
  opacity: number;
}

/**
 * @internal
 *
 * @param colorPalette - to check if it is a custom color palette
 */
export function isCustomColorPalette(
  colorPalette: ColorPalette | CustomColorPalette | ColoredRange[],
): colorPalette is CustomColorPalette {
  return (
    typeof colorPalette === 'object' &&
    colorPalette !== null &&
    (!Array.isArray(colorPalette) || colorPalette.length > 0)
  );
}

/**
 * @internal
 *
 * @param colorPalette - to check if it is a custom color record palette
 */
export function isCustomColorRecordPalette(
  colorPalette: ColorPalette | CustomColorPalette,
): colorPalette is Record<string, string> {
  return !Array.isArray(colorPalette);
}

/**
 * @internal
 *
 * @param colorPalette - to check if the color palette should be applied automatically
 */
export const shouldApplyAutomatically = (
  colorPalette: ColorPalette,
): colorPalette is AutomaticColorPalette => {
  // @ts-expect-error -- Typescript complains because `ColorPalette` is a superset of `AutomaticColorPalette`, but the condition is meant for runtime
  return automaticColoringOptions.includes(colorPalette);
};

